INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Pratiques managériales avec IA', 'Formation sur l’utilisation de l’IA pour optimiser la prospection, la relation client et augmenter les ventes.', 2, 250000.00, 'entreprise', '2026-08-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre le rôle et les opportunités de l’IA dans la vente\n• Identifier les outils IA pour optimiser la prospection et la fidélisation\n• Développer des stratégies concrètes pour augmenter le chiffre d’affaires\n• Exploiter les données clients pour anticiper leurs besoins\n• Personnaliser les offres et améliorer la conversion\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les opportunités de l’IA dans la vente et le marketing, identifier les outils IA pour optimiser la prospection et la relation client, développer des stratégies concrètes pour augmenter le chiffre d’affaires et exploiter les données clients pour personnaliser les offres.\n\n--- PRÉREQUIS ---\nConnaissances de base en vente et marketing. Une familiarité avec les outils numériques est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA pour la vente\nModule 2 : Prospection et génération de leads avec l’IA\nModule 3 : Personnalisation et optimisation de l’expérience client\nModule 4 : Optimisation de la performance commerciale\nModule 5 : Automatisation et gain de productivité\nModule 6 : Éthique et limites de l’IA dans la vente\nModule 7 : Atelier final – Plan d’action pour augmenter ses ventes\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nManagers commerciaux, responsables marketing, chefs d’équipe, consultants en stratégie commerciale, toute personne impliquée dans la vente et le développement commercial.\n\n--- MÉTHODES ---\nPrésentations interactives, ateliers pratiques, études de cas, simulations, travaux de groupe et feedback personnalisé.\n\n--- SUPPORTS ---\nSlides interactives, vidéos démonstratives, CRM intelligents, chatbots, outils de scoring, fiches pratiques et guides d’utilisation des outils IA.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
